// in cli/bench/deno_common.js
async function benchWriteFile() {
  const input = new TextEncoder().encode("long-string".repeat(999_999));
  const tempDir = Deno.makeTempDirSync();
  let i = 0;
  await benchAsync("write_file_large", 100, async () => {
    await Deno.writeFile(`${tempDir}/${i++}.txt`, input);
